function generateUniqueId() { return "xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx".replace(/[xy]/g, (function (t) { const e = 16 * Math.random() | 0; return ("x" === t ? e : 3 & e | 8).toString(16) })) } function getVisitorId() { const t = "visitor_id_session"; let e = localStorage.getItem(t); return e || (e = generateUniqueId(), localStorage.setItem(t, e)), e } const currentVisitorId = getVisitorId(); let getHostname = new URL(window.location); async function sha256(t) { const e = await crypto.subtle.digest("SHA-256", (new TextEncoder).encode(t)); return Array.from(new Uint8Array(e)).map((t => t.toString(16).padStart(2, "0"))).join("") } async function trackVisitor(t, e) { fetch("https://count.spairum.my.id/api/track/unique", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ host: t, visitorId: e }) }) } async function trak(t) { let e = await sha256(t); document.cookie.split(";").some((t => t.trim().startsWith(`${e}=`))) || (trackVisitor(t, currentVisitorId), document.cookie = `${e}=${currentVisitorId}; path=/; max-age=86400;`) } function getTrackUnique(t) { return fetch("https://count.spairum.my.id/api/analytics/unique/" + t, {}).then((t => t.json())) } function getTrackbyDate(t, e) { return fetch("https://count.spairum.my.id/api/analytics/track/" + t + "/" + e, {}).then((t => t.json())) } async function views() { let t = getHostname.href; if (!document.cookie.split(";").some((e => e.trim().startsWith(`${t}=`)))) { let e = await fetch("https://count.spairum.my.id/api/track/view", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ host: t }) }); e = await e.json(), console.log(e), document.cookie = `${t}=${e.views}; path=/; max-age=60;` } } console.log("Session Visitor ID:", currentVisitorId), trak(getHostname.hostname), trak(getHostname.hostname + "-" + getHostname.pathname.split("/")[1]), views();